#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define MAXN 65536
#define MAXM 200000
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int **A = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            A[i] = (int *)malloc(M * sizeof(int));
        }
        int *b = (int *)malloc(M * sizeof(int));
        for (int i = 0; i < M; i++) {
            int Xi, Yi, Zi;
            scanf("%d %d %d", &Xi, &Yi, &Zi);
            for (int j = Xi - 1; j < Yi; j++) {
                A[j][i] = 1;
            }
            b[i] = Zi;
        }
        // Gaussian Elimination
        for (int i = 0; i < N; i++) {
            int maxEl = abs(A[i][i]);
            int maxRow = i;
            for (int k = i + 1; k < N; k++) {
                if (abs(A[k][i]) > maxEl) {
                    maxEl = abs(A[k][i]);
                    maxRow = k;
                }
            }
            // Swap maximum row with current row
            for (int j = 0; j < M; j++) {
                int tmp = A[maxRow][j];
                A[maxRow][j] = A[i][j];
                A[i][j] = tmp;
            }
            int tmp = b[maxRow];
            b[maxRow] = b[i];
            b[i] = tmp;
            // Make all rows below this one 0 in current column
            for (int k = i + 1; k < N; k++) {
                int c = -A[k][i] / A[i][i];
                for (int j = 0; j < M; j++) {
                    if (i == j) {
                        A[k][j] = 0;
                    } else {
                        A[k][j] += c * A[i][j];
                    }
                }
                b[k] += c * b[i];
            }
        }
        // Solve equation Ax=b for an upper triangular matrix A
        int *x = (int *)malloc(N * sizeof(int));
        for (int i = N - 1; i >= 0; i--) {
            x[i] = b[i];
            for (int k = i + 1; k < N; k++) {
                x[i] -= A[i][k] * x[k];
            }
            x[i] /= A[i][i];
        }
        // Print solution
        for (int i = 0; i < N; i++) {
            printf("%d ", x[i]);
        }
        printf("\n");
    }
    return 0;
}

